class Dangerous {
    FILE* file;
public:
    Dangerous(const char* filename) {
        file = fopen(filename, "r");
        if (!file) throw std::runtime_error("Open failed");
    }

    ~Dangerous() {
        if (fclose(file) != 0) {
            throw std::runtime_error("Close failed");  // ❌ NEVER throw from destructor
        }
    }
};

void problematic() {
