void useUniquePtr() {
    auto closer = [](FILE* f) {
        if (f) {
            std::cout << "Lambda closing file\n";
            fclose(f);
        }
    };

    std::unique_ptr<FILE, decltype(closer)> file(
        fopen("test.txt", "w"), 
        closer
    );

    if (file) {
        fprintf(file.get(), "Hello World\n");
    }
}  // File automatically closed via custom deleter

