    TrackedObject obj;
    return obj;  // Named: NRVO optional, may move
}

TrackedObject optional2(bool flag) {
    TrackedObject obj1, obj2;
    return flag ? obj1 : obj2;  // Multiple paths: NRVO prevented, will move
