    auto new_end = std::remove(v.begin(), v.end(), 2);
    v.erase(new_end, v.end());

    // Now v contains: {1, 3, 4, 5}

    // Alternative: remove_if with lambda
    v.erase(
        std::remove_if(v.begin(), v.end(), 
            [](int x) { return x % 2 == 0; }),
        v.end()
