    people.insert({"Alice", 30});
    people.insert({"Bob", 25});
    people.insert({"Charlie", 30});
    people.insert({"David", 25});

    // Sorted by age first, then name
    for (const auto& p : people) {
        std::cout << p.name << " (" << p.age << ")\n";
    }
