    auto lambda = [ptr = std::move(ptr)]() mutable {
        (*ptr)++;
        std::cout << "Value: " << *ptr << "\n";
    };

    // ptr is now null
    std::cout << "Original ptr is null: " << (ptr == nullptr) << "\n";

    lambda();  // Prints 43
    lambda();  // Prints 44

