std::function<int(int)> factorial = [&factorial](int n) {
    return (n <= 1) ? 1 : n * factorial(n - 1);
};
std::cout << factorial(5) << "\n";  // 120

// ✅ Alternative: separate helper function
auto makeFactorial() {
    struct Helper {
        int operator()(int n) {
            return (n <= 1) ? 1 : n * (*this)(n - 1);
        }
    };
    return Helper();
