    static constexpr size_t size = 0;
    using First = void;
};

// Partial specialization: at least one type
template<typename Head, typename... Tail>
class TypeList<Head, Tail...> {
public:
    static constexpr size_t size = 1 + sizeof...(Tail);
    using First = Head;
    using Rest = TypeList<Tail...>;
};

// Usage
